import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';

const detectHallucinations = async (messages: any[]) => {
  const result = await streamText({
    model: openai('gpt-4o'),
    messages,
    experimental_streamingTokens: true,
  });

  let confidenceDrop = false;
  let tokenCount = 0;

  for await (const chunk of result.textStream) {
    const tokens = await result.tokenStream.next();
    if (tokens.value?.logprobs?.topLogprobs[0]?.logprob < -0.8) {
      confidenceDrop = true;
      console.warn('Hallucination detected at token', tokenCount);
    }
    tokenCount++;
  }

  return { hasHallucination: confidenceDrop };
};

