import { generateText } from 'ai';
import { openai, anthropic } from '@ai-sdk/providers';

const testStructuredOutput = async () => {
  const providers = [
    { name: 'openai', model: openai('gpt-4o-mini') },
    { name: 'anthropic', model: anthropic('claude-3-5-sonnet-20240620') }
  ];

  const inconsistencies = [];

  for (const { name, model } of providers) {
    try {
      const { text } = await generateText({
        model,
        schema: z.object({ name: z.string(), age: z.number() }),
        prompt: 'Return structured data about John who is 30 years old.'
      });
      const parsed = JSON.parse(text);
      if (!parsed.age || typeof parsed.age !== 'number') {
        inconsistencies.push(`${name}: Invalid number type`);
      }
    } catch (error) {
      inconsistencies.push(`${name}: Parsing failed`);
    }
  }

  return inconsistencies;
};

