import { createStreamableValue } from 'ai/rsc';

export async function StreamingAgent({ messages }: { messages: any[] }) {
  const ui = createStreamableValue('');

  (async () => {
    const result = await streamText({
      model: openai('gpt-4o'),
      messages,
      experimental_streamingTokens: true,
    });

    let buffer = '';
    let lowConfidenceCount = 0;

    for await (const chunk of result.textStream) {
      const tokens = await result.tokenStream.next();
      const logprob = tokens.value?.logprobs?.topLogprobs[0]?.logprob || 0;

      if (logprob < -0.7) {
        lowConfidenceCount++;
        if (lowConfidenceCount > 3) {
          ui.update('⚠️ Potential hallucination detected. Verifying...');
          continue;
        }
      } else {
        lowConfidenceCount = 0;
      }

      buffer += chunk;
      ui.update(buffer);
    }

    ui.done();
  })();

  return ui.value;
}

import { z } from 'zod';
import { tool } from 'ai/rsc';

const safeCalculatorTool = tool({
  description: 'Safe calculator with validation',
  parameters: z.object({
    expr: z.string().regex(/^[0-9+\-*/().\s]+$/, 'Invalid expression')
  }),
  execute: async ({ expr }) => {
    const safeEval = (expression: string) => {
      // Sandboxed evaluation
      const func = new Function(`return (${expression})`);
      return func();
    };

    try {
      const result = safeEval(expr);

      const validated = z.number().safeParse(result);
      if (!validated.success) {
        return {
          error: 'Result not a valid number',
          fallback: 0,
          valid: false
        };
      }

      return { result: validated.data, valid: true };
    } catch (error) {
      return {
        error: 'Calculation failed',
        fallback: 0,
        valid: false
      };
    }
  }
});

import { generateText } from 'ai';
import { openai } from '@ai-sdk/openai';

export async function timeoutAgent(messages: any[]) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 25000); // 25s edge limit

  try {
    const result = await Promise.race([
      generateText({
        model: openai('gpt-4o'),
        messages,
        abortSignal: controller.signal,
        maxTokens: 2000,
      }),
      new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error('Agent timeout')), 25000)
      )
    ]);

    clearTimeout(timeoutId);
    return { success: true, content: result.text };

  } catch (error: any) {
    clearTimeout(timeoutId);
    if (error.name === 'AbortError') {
      return {
        success: false,
        content: 'Task too complex for current limits. Try simplifying your request.',
        retryable: true
      };
    }
    throw error;
  }
}

